import { BedrockAgentRuntimeClient, InvokeAgentCommand } from '@aws-sdk/client-bedrock-agent-runtime';
import { Vex } from 'vex-sdk';

const bedrock = new BedrockAgentRuntimeClient({ region: 'us-east-1' });
const vex = new Vex({ apiKey: 'your-vex-key' });

const policy = {
  rules: [
    { type: 'block', name: 'cve_validation', pattern: /CVE-\d+-\d+(?!\s*\(verified\))/ },
    { type: 'require', name: 'session_persisted', field: 'sessionState', minLength: 100 }
  ]
};

const command = new InvokeAgentCommand({
  agentId: 'YOUR_AGENT_ID',
  agentAliasId: 'YOUR_ALIAS_ID',
  sessionId: 'session-123',
  inputText: 'Generate advisory for recent Log4j vuln'
});

const agentResponse = await bedrock.send(command);
const verified = await vex.verify(JSON.stringify(agentResponse.completion), policy);

if (verified.valid) {
  console.log('Approved:', verified.output);
} else {
  console.error('Violations:', verified.violations);
}

import boto3
import vex

bedrock = boto3.client('bedrock-agent-runtime')
vex_client = vex.Client(api_key="your-vex-key")

kb_policy = vex.Policy({
    "rules": [
        {"type": "require", "name": "min_docs", "field": "retrievedDocuments", "min_length": 3},
        {"type": "block", "name": "no_pii", "pattern": r"\b(?:SSN|passport|credit_card)\b"}
    ]
})

response = bedrock.invoke_agent(
    agentId='THREAT_INTEL_AGENT',
    sessionId='incident-456',
    inputText='Retrieve docs for ransomware C2: 192.168.1.100'
)

# Extract KB retrieval from agent trace
kb_result = response['trace']['retrievalResults']
verified_kb = vex_client.verify(kb_result, kb_policy)

if verified_kb.valid:
    # Proceed with agent reasoning
    final_response = bedrock.invoke_agent(..., inputText='Analyze retrieved docs')
else:
    raise ValueError(f"KB retrieval failed validation: {verified_kb.violations}")
